// Verify Slack signature (security)
const crypto = require('crypto');

const input = $input.first();
const headers = input.headers || {};
const body = input.body || '';

const slackSignature = headers['x-slack-signature'];
const slackTimestamp = headers['x-slack-request-timestamp'];
const signingSecret = process.env.SLACK_SIGNING_SECRET;

// Skip verification if no signing secret configured
if (!signingSecret) {
  return { json: { verified: true, warning: 'No signing secret configured', body } };
}

// Check timestamp to prevent replay attacks (5 min window)
const now = Math.floor(Date.now() / 1000);
if (Math.abs(now - parseInt(slackTimestamp)) > 300) {
  throw new Error('Request timestamp too old');
}

// Verify signature
const sigBasestring = `v0:${slackTimestamp}:${body}`;
const mySignature = 'v0=' + crypto
  .createHmac('sha256', signingSecret)
  .update(sigBasestring)
  .digest('hex');

if (!crypto.timingSafeEqual(Buffer.from(mySignature), Buffer.from(slackSignature || ''))) {
  throw new Error('Invalid Slack signature');
}

return { json: { verified: true, body } };

// Parse Slack command payload
const input = $input.first().json;

// Handle verification failure
if (input.error) {
  return {
    json: {
      response_type: 'ephemeral',
      text: ':x: Request verification failed',
      error: true
    }
  };
}

const body = input.body || '';
const params = new URLSearchParams(body);

const command = params.get('command') || '';
const text = params.get('text') || '';
const userId = params.get('user_id') || '';
const userName = params.get('user_name') || '';
const channelId = params.get('channel_id') || '';
const responseUrl = params.get('response_url') || '';
const triggerId = params.get('trigger_id') || '';

const parts = text.trim().split(/\s+/);
const subcommand = parts[0] || 'help';
const args = parts.slice(1);

const commandRoutes = {
  '/hwc': 'hwc',
  '/media': 'media',
  '/arr': 'arr',
  '/dl': 'download',
  '/sys': 'system',
  '/cam': 'camera',
  '/ai': 'ai',
  '/docs': 'documents',
  '/finance': 'finance',
  '/books': 'books'
};

const domain = commandRoutes[command] || 'hwc';

return {
  json: {
    domain,
    command,
    subcommand,
    args,
    argsText: args.join(' '),
    user: { id: userId, name: userName },
    channelId,
    responseUrl,
    triggerId,
    timestamp: new Date().toISOString()
  }
};

// System commands - REAL implementations
const input = $input.first().json;
const { subcommand, args, responseUrl } = input;

let response = { response_type: 'ephemeral', text: '' };
let asyncAction = null;

switch (subcommand) {
  case 'status':
    // Trigger health check workflow and return immediate ack
    response.text = ':hourglass: Checking system health...';
    asyncAction = {
      type: 'health-check',
      responseUrl
    };
    break;

  case 'disk':
    response.text = ':hourglass: Checking disk usage...';
    asyncAction = {
      type: 'disk-check',
      responseUrl
    };
    break;

  case 'logs':
    if (!args[0]) {
      response.text = ':warning: Usage: `/sys logs <service>`\nExample: `/sys logs caddy`';
    } else {
      response.text = `:hourglass: Fetching logs for ${args[0]}...`;
      asyncAction = {
        type: 'logs',
        service: args[0],
        responseUrl
      };
    }
    break;

  case 'restart':
    if (!args[0]) {
      response.text = ':warning: Usage: `/sys restart <service>`';
    } else {
      response.text = `:warning: Are you sure you want to restart *${args[0]}*?\nThis is a potentially disruptive action.`;
      response.blocks = [
        { type: 'section', text: { type: 'mrkdwn', text: response.text } },
        {
          type: 'actions',
          elements: [
            {
              type: 'button',
              text: { type: 'plain_text', text: 'Confirm Restart' },
              style: 'danger',
              action_id: `restart_${args[0]}`,
              value: args[0]
            },
            {
              type: 'button',
              text: { type: 'plain_text', text: 'Cancel' },
              action_id: 'cancel'
            }
          ]
        }
      ];
    }
    break;

  case 'help':
  default:
    response.blocks = [
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: '*System Commands*\n\n' +
            '`/sys status` - System health overview\n' +
            '`/sys disk` - Disk usage summary\n' +
            '`/sys logs <service>` - Recent service logs\n' +
            '`/sys restart <service>` - Restart a service (with confirmation)'
        }
      }
    ];
    response.text = 'System Commands';
}

return { json: { ...response, asyncAction, originalCommand: input } };

// Arr stack commands
const input = $input.first().json;
const { subcommand, args, argsText, responseUrl } = input;

let response = { response_type: 'ephemeral', text: '' };
let asyncAction = null;

switch (subcommand) {
  case 'status':
    response.text = ':hourglass: Checking *arr stack status...';
    asyncAction = { type: 'arr-status', responseUrl };
    break;

  case 'queue':
    response.text = ':hourglass: Fetching download queue...';
    asyncAction = { type: 'arr-queue', responseUrl };
    break;

  case 'search':
    if (!argsText) {
      response.text = ':warning: Usage: `/arr search <query>`';
    } else {
      response.text = `:mag: Searching for "${argsText}"...`;
      asyncAction = { type: 'arr-search', query: argsText, responseUrl };
    }
    break;

  case 'missing':
    response.text = ':hourglass: Checking missing content...';
    asyncAction = { type: 'arr-missing', responseUrl };
    break;

  case 'help':
  default:
    response.blocks = [
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: '*Arr Stack Commands*\n\n' +
            '`/arr status` - Health of Sonarr, Radarr, Lidarr, etc\n' +
            '`/arr queue` - Current download queue\n' +
            '`/arr search <query>` - Search all libraries\n' +
            '`/arr missing` - Missing content summary'
        }
      }
    ];
    response.text = 'Arr Stack Commands';
}

return { json: { ...response, asyncAction, originalCommand: input } };

// Download commands
const input = $input.first().json;
const { subcommand, responseUrl } = input;

let response = { response_type: 'ephemeral', text: '' };
let asyncAction = null;

switch (subcommand) {
  case 'status':
    response.text = ':hourglass: Checking download clients...';
    asyncAction = { type: 'dl-status', responseUrl };
    break;

  case 'queue':
    response.text = ':hourglass: Fetching active downloads...';
    asyncAction = { type: 'dl-queue', responseUrl };
    break;

  case 'vpn':
    response.text = ':hourglass: Checking VPN status...';
    asyncAction = { type: 'dl-vpn', responseUrl };
    break;

  case 'help':
  default:
    response.blocks = [
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: '*Download Commands*\n\n' +
            '`/dl status` - qBittorrent, SABnzbd status\n' +
            '`/dl queue` - Active downloads\n' +
            '`/dl vpn` - Gluetun VPN status'
        }
      }
    ];
    response.text = 'Download Commands';
}

return { json: { ...response, asyncAction, originalCommand: input } };

// Main help menu
const input = $input.first().json;

return {
  json: {
    response_type: 'ephemeral',
    blocks: [
      {
        type: 'header',
        text: { type: 'plain_text', text: ':desktop_computer: HWC Server Commands', emoji: true }
      },
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: '`/sys` - System & infrastructure\n' +
            '`/arr` - Sonarr, Radarr, Lidarr, Prowlarr\n' +
            '`/dl` - Downloads (qBit, SAB, VPN)\n' +
            '`/media` - Media services (Jellyfin, Immich)\n' +
            '`/cam` - Surveillance (Frigate)\n' +
            '`/ai` - AI services (Ollama)\n' +
            '`/docs` - Documents (Paperless)\n' +
            '`/finance` - Finance (Firefly)\n' +
            '`/books` - Books & audiobooks'
        }
      },
      {
        type: 'context',
        elements: [{ type: 'mrkdwn', text: 'Add `help` to any command for details' }]
      }
    ],
    text: 'HWC Server Commands',
    originalCommand: input
  }
};

// Execute async action and send result to response_url
const input = $input.first().json;
const action = input.asyncAction;

let result = { text: ':x: Unknown action', blocks: [] };

try {
  switch (action.type) {
    case 'health-check':
      // Call health check webhook
      const healthResponse = await this.helpers.httpRequest({
        method: 'POST',
        url: 'http://127.0.0.1:5678/webhook/health-check',
        json: true
      });

      const { summary, unhealthyServices } = healthResponse;
      const statusEmoji = summary.unhealthy === 0 ? ':white_check_mark:' : ':warning:';

      result.blocks = [
        {
          type: 'header',
          text: { type: 'plain_text', text: `${statusEmoji} System Health`, emoji: true }
        },
        {
          type: 'section',
          fields: [
            { type: 'mrkdwn', text: `*Healthy:*\n${summary.healthy}` },
            { type: 'mrkdwn', text: `*Unhealthy:*\n${summary.unhealthy}` }
          ]
        }
      ];

      if (unhealthyServices?.length > 0) {
        result.blocks.push({
          type: 'section',
          text: {
            type: 'mrkdwn',
            text: '*Down:*\n' + unhealthyServices.map(s => `:x: ${s.name}`).join('\n')
          }
        });
      }
      result.text = `${statusEmoji} ${summary.healthy}/${summary.total} services healthy`;
      break;

    case 'disk-check':
      const diskResult = await this.helpers.executeCommand('df -h / /mnt/media /mnt/hot 2>/dev/null | tail -n +2');
      const diskLines = diskResult.stdout.trim().split('\n').map(line => {
        const parts = line.split(/\s+/);
        return `${parts[5]}: ${parts[4]} used (${parts[2]}/${parts[1]})`;
      });

      result.blocks = [{
        type: 'section',
        text: { type: 'mrkdwn', text: '*Disk Usage*\n```' + diskLines.join('\n') + '```' }
      }];
      result.text = 'Disk Usage';
      break;

    case 'dl-vpn':
      const vpnResult = await this.helpers.httpRequest({
        method: 'GET',
        url: 'http://127.0.0.1:8000/v1/publicip/ip',
        returnFullResponse: true
      }).catch(() => ({ body: 'Unknown' }));

      result.blocks = [{
        type: 'section',
        text: { type: 'mrkdwn', text: `*VPN Status*\nPublic IP: \`${vpnResult.body || 'Unknown'}\`` }
      }];
      result.text = 'VPN Status';
      break;

    default:
      result.text = `:construction: Action \`${action.type}\` not yet implemented`;
  }
} catch (error) {
  result.text = `:x: Error: ${error.message}`;
}

return { json: { responseUrl: action.responseUrl, ...result } };
